[{"pg_get_functiondef":"CREATE OR REPLACE FUNCTION public.admin_audit_insert(p_actor_id uuid, p_action text, p_target_type text DEFAULT NULL::text, p_target_id text DEFAULT NULL::text, p_before jsonb DEFAULT NULL::jsonb, p_after jsonb DEFAULT NULL::jsonb, p_metadata jsonb DEFAULT NULL::jsonb, p_ip text DEFAULT NULL::text, p_user_agent text DEFAULT NULL::text)
 RETURNS uuid
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'auth'
AS $function$
DECLARE
  v_id UUID;
  v_email TEXT;
BEGIN
  IF NOT public.is_admin(p_actor_id) THEN
    RAISE EXCEPTION 'not_admin';
  END IF;
  SELECT email INTO v_email FROM public.profiles WHERE id = p_actor_id;
  INSERT INTO public.audit_log (actor_id, actor_email, action, target_type, target_id, before, after, metadata, ip_address, user_agent)
  VALUES (p_actor_id, v_email, p_action, p_target_type, p_target_id, p_before, p_after, p_metadata, p_ip, p_user_agent)
  RETURNING id INTO v_id;
  RETURN v_id;
END;
$function$
"},{"pg_get_functiondef":"CREATE OR REPLACE FUNCTION public.expire_credits()
 RETURNS integer
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE v_count integer := 0; v_b record; v_balance_after integer;
BEGIN
  FOR v_b IN SELECT id, user_id, remaining_credits FROM public.credit_buckets WHERE expires_at IS NOT NULL AND expires_at <= clock_timestamp() AND remaining_credits > 0 ORDER BY user_id, granted_at FOR UPDATE LOOP
    PERFORM pg_advisory_xact_lock(hashtextextended(v_b.user_id::text, 0));
    UPDATE public.credit_buckets SET remaining_credits = 0 WHERE id = v_b.id;
    SELECT COALESCE(SUM(remaining_credits),0) INTO v_balance_after FROM public.credit_buckets WHERE user_id = v_b.user_id;
    INSERT INTO public.credit_transactions (user_id, type, credits, bucket_id, ref_type, ref_id, balance_after, metadata)
      VALUES (v_b.user_id, 'expiry', v_b.remaining_credits, v_b.id, 'bucket', v_b.id::text, v_balance_after, jsonb_build_object('source','expiry'));
    v_count := v_count + 1;
  END LOOP;
  RETURN v_count;
END;$function$
"}]
